#include <iostream>
#include <string>

int main()
{
    int n{};
    std::cin >> n;
    std::cin.ignore();

    if (n == 0)
    {
        std::cout << "No names provided." << '\n';
        return 0;
    }

    for (int i{ 0 }; i < n; ++i)
    {
        std::string name{};
        std::getline(std::cin, name);
        std::cout << "Hello, " << name << "!" << '\n';
    }

    return 0;
}

