#include <iostream>
#include <string>

int main()
{
    int n{};
    std::cin >> n;
    std::cin.ignore();

    int sum{ 0 };
    int max{ 0 };
    for (int i{ 0 }; i < n; ++i)
    {
        std::string arg{};
        std::getline(std::cin, arg);
        int value{ std::stoi(arg) };
        sum += value;
        if (i == 0 || value > max)
            max = value;
    }

    std::cout << "Sum: " << sum << '\n';
    std::cout << "Max: " << max << '\n';

    return 0;
}
